%[text] ![](text:image:804e)
clear all
% States
syms theta theta_dot theta_dot_dot J u
theta %[output:0aeb6bd3]
theta_dot %[output:0c8f550f]
theta_dot_dot %[output:829449c4]
StateVector = [theta; theta_dot] %[output:96ff02f7]
%[text] **Problem 1.1: System in CT State Space**
% Define the continuous-time state-space representation
A = [0 1; 0 0];
B = [0; 1]; %for J=1
C = eye(2);
D = zeros(2, 1);
Ts = 0.25 %[output:542771bc]
LTI_sys = ss(A,B,C,D) %[output:5233cbf1]
x0 = [pi/2; 0] %IC %[output:1fb4e4c9]
xN = [0; 0];   %TC
%[text] **Problem 1.2: System in DT State Space**
LTI_sys_d = c2d(LTI_sys,Ts) %Discrete System %[output:8b733507]
Ad = LTI_sys_d.A %[output:7ba717ab]
Bd = LTI_sys_d.B %[output:2d838297]
Cd = LTI_sys_d.C %[output:7d93eab0]
Dd = LTI_sys_d.D %[output:3c8ffe14]
%[text] **Problem 1.3: Closed Loop MPC Formulation**
%Cost Function f_cost
% f_cost = @(u) sum(u.^2)
Ncost=20; %optimizes cost over 20 horizon
Nterminal = 20; %optimization constraint, Nterminal = i, x must reach xN by i on the horizon
U_guess = rand(Ncost,1);

solver_options = optimoptions('fmincon', ...
    'Display','iter', ...
    'Algorithm','sqp', ...
    'MaxFunctionEvaluations',5e4, ...
    'TolFun',1e-9, ...
    'TolCon',1e-9);

function J = f_cost(U,Ncost)
% U is a vertically concatenated vector of control input vectors u.
% Our system is single input so ui is 1x1
% For L input system & N horizon, U has dimension LN x 1. Function
% returns cost for the series of inputs over the horizon (applies u1,
% u2, ..., uN)

J = 0;
    for k=0:Ncost-1
        u_inc = U(k+1);
        J_inc = sum(u_inc.^2);
        J = J + J_inc;
    end
end

function [c, ceq] = nonlcon(U, Ncost, Nterminal, x0, xN, Ad, Bd)
% c <= 0 & ceq == 0 are given to fmincon as constraints on the optimization
% where c & ceq are nonlinear functions of U, the optimization vector (stack of inputs)
% x_prediction moves along horizon with system dynamics to N where
% terminal constraint x(:,N) = xN defined above is set using ceq.
% This constraint is linear so it should probably not be under nonlcon
% fmincon input, but oh well

    x_prediction = [x0 zeros(2,Ncost-1)];
    for k=0:Ncost-1
        u_inc = U(k+1);
        x_prediction(:,k+2) = Ad*x_prediction(:,k+1) + Bd*u_inc;
    end

% Terminal Constraint: x_prediction(:,N) = x0, solver takes ceq = 0 as
% constraint:

%the code below until "%ends_here" is not really used, I just wanted to see
%what would happen if I moved the terminal constraint closer and closer w/
%each optimization, to show x would reach xN in exactly N steps.
number_of_xN_on_horizon = Ncost+1 - Nterminal;
vector_of_xN = zeros(2,number_of_xN_on_horizon);

% vector_of_xN = [xN, xN, xN, ... xN] with number_of_xN_on_horizon columns
for i=1:number_of_xN_on_horizon
    vector_of_xN(:,i) = xN;
end

%ends_here
ceq = x_prediction(:,Nterminal:Ncost)-vector_of_xN;
c=[];
end

%Anonymous cost and constraint function handles so that the solver can run
%different values of U, and the other arguments are grabbed from
%earlier in the script. Lets find U_optimal at x0 and plot
f_cost_anonymous = @(U) f_cost(U,Ncost) %[output:566a372e]
nonlcon_anonymous = @(U) nonlcon(U, Ncost, Nterminal, x0, xN, Ad, Bd) %[output:7f6df947]
U_optimal1 = fmincon(f_cost_anonymous,U_guess,[],[],[],[],[],[],nonlcon_anonymous) %[output:227b90e1] %[output:6cafdea9]

x_disc = [x0, zeros(2,Ncost-1)] %[output:4d2fcda6]
for k=1:Ncost-1
x_disc(:,k+1) = Ad*x_disc(:,k) + Bd*U_optimal1(k);
end

plot(x_disc(1,:),x_disc(2,:)) %[output:7672e668]
hold on %[output:7672e668]
scatter(x_disc(1,Ncost), x_disc(2,Ncost),'Color','r') %[output:7672e668]
xlabel('\theta (rad)'); ylabel('\theta_d_o_t (rad/s)'); %[output:7672e668]
title('Predicted MPC Trajectory from U_o_p_t_i_m_a_l at x_0'); %[output:7672e668]
figure;
%[text] **Problem 1.3: Closed Loop MPC Trajectory**
%Close the loop and run for 30 time steps to see if the trajectory
%converges to xN. Input comes from the nonlinear LQN solution U, the
%solution to the quadratic program with terminal constraint.
%(first u in U_optimal at each optimization)

x_cl = [x0 zeros(2,Ncost)];
x_next = x0;
loops = 20;
U_optimal = zeros(Ncost,loops);
u_applied = zeros(1,loops);
for k = 1:loops %[output:group:2a24f4bd]
    
    % Define the constraint with current state
    nonlcon_current = @(U) nonlcon(U, Ncost, Nterminal, x_next, xN, Ad, Bd);
    %Nterminal = Ncost-k;    %If I keep bringing the terminal state closer
    %on the horizon, convergence to xN will happen in N steps. But that
    %defeats the purpose. we want the moving horizon, thats the point of
    %MPC!!!!

    % Solve MPC problem from current state
    U_optimal(:,k) = fmincon(f_cost_anonymous, U_guess, [],[],[],[],[],[], nonlcon_current, solver_options); %[output:78ac815d] %[output:31c41284] %[output:4eb00789] %[output:94d1136c] %[output:116f87a9] %[output:4e2e1a43] %[output:1f57ef3d] %[output:88b6f8fe] %[output:6d43addb] %[output:16511a31] %[output:4ed1254b] %[output:29ac6bdb] %[output:6642a638] %[output:955963b2] %[output:72a2da10] %[output:2213abef] %[output:2809ce1f] %[output:079cae9a] %[output:0ea75a51] %[output:5761dab5]
    
    % Apply first control input
    u_applied(:,k) = U_optimal(1,k);
    
    % Update system state
    x_next = Ad*x_next + Bd*u_applied(:,k);
    
    % Store closed-loop trajectory
    x_cl(:,k+1) = x_next;
    
    % Optionally update initial guess for next optimization
    % U_guess = [U_optimal(2:end); U_optimal(end)];
    U_guess = rand(Ncost,1) %[output:06e6de66] %[output:761d53f0] %[output:4ac994ec] %[output:39de2643] %[output:2d317734] %[output:8ce6aa26] %[output:535132d3] %[output:32bdc06b] %[output:9d85b96d] %[output:7bad6f4c] %[output:41d313e6] %[output:18df1606] %[output:221f5cac] %[output:91eec19f] %[output:3628f89b] %[output:604f5e23] %[output:6b2db8f7] %[output:5a87b509] %[output:52456247] %[output:0069f439]
end %[output:group:2a24f4bd]
figure; %[output:90ac4fa5]
