%[text] **Problem 1.4: LQ-MPC Solution using State Transformation Approach (KKT Necessary Conditions)**
% For LQN (linear quadratic finite horizon) with only terminal state
% constraints (no other constraints on input or state vector, apart from
% the forward euler dynamics)

% First define the hamiltonian
syms x_k Q u_k R H  P_k P_k_plus_1 f_k x_k_plus_1 A_k B_k
Hamiltonian = H == 0.5*(transpose(x_k)*Q*x_k + transpose(u_k)*R*u_k) + transpose(P_k_plus_1*f_k) %[output:4e34a4ed]

% Necessary Conditions include:
    % Equation of Motion
    Motion = [ %[output:group:1f308953] %[output:867b1db8]
    f_k == A_k*x_k + B_k*u_k %[output:867b1db8]
    x_k_plus_1 == f_k %[output:867b1db8]
    ] %[output:group:1f308953] %[output:867b1db8]
        % Update H
        Hamiltonian = subs(Hamiltonian,lhs(Motion), rhs(Motion));
    % Adjoint
    Adjoint = P_k == gradient(rhs(Hamiltonian), x_k) %[output:788709cd]
    % Stationarity
    Stationarity = gradient(rhs(Hamiltonian),u_k) == 0 %[output:877f85df]
    % Transversality:
%[text] ![](text:image:2e90)
% From cost function:
R = 1;
Q = zeros(2);
% Horizon
N=20;

function [u_horizon, x_horizon, p_horizon] = GetKKTHorizon(x0, Ad, Bd, Q, R, N, xN)
    
    % Evolution:
    phi = [Ad+Bd*inv(R)*transpose(Bd)*inv(Ad')*Q, -Bd*inv(R)*transpose(Bd)*inv(Ad'); ...
          -transpose(Ad)*Q, inv(transpose(Ad))];
    phiN = phi^N;
    
    phiN_11 = phiN(1:2,1:2);
    phiN_12 = phiN(1:2,3:4);
    phiN_21 = phiN(3:4,1:2);
    phiN_22 = phiN(3:4,3:4);
    
    % Compute p0 from x0
    p0 = (phiN_12)\(xN - phiN_11*x0);
    
    % Initialize
    x_horizon = [x0,zeros(2,N-1)];
    p_horizon = [p0,zeros(2,N-1)];
    u_horizon = zeros(1,N);
    
    for i=1:N
    % Starts with x0 and p0
        x_prev = x_horizon(:,i);
        p_prev = p_horizon(:,i);
        xp_prev = [x_prev; p_prev];
    %Find the next augmented xp matrix
        xp_current = phi*xp_prev;
    %Store in x and p horizon vectors
        x_horizon(:,i+1) = xp_current(1:2,:);
        p_horizon(:,i+1) = xp_current(3:4,:);
    
    %Calculate optimal u_k which leads to x_k+1. No need for u_k at k=N.
        if i ~= N
            u_horizon(:,i) = -R \ Bd'*p_horizon(:,i+1);
        end
    end
end

% Wrap with an anonymous function
GetHorizon = @(x) GetKKTHorizon(x, Ad, Bd, Q, R, N, xN);

[u_horizon, x_horizon, p_horizon] = GetHorizon(x0) %[output:5055fa05] %[output:953e414c] %[output:1fb4a5b1]

% Plot the open loop sequence from KKT solution, horizon N=20, starting @x0
figure; %[output:785034c0]
subplot(3,1,1); %[output:785034c0]
plot(0:N, x_horizon(1,:), '-o'); hold on; plot(0:N, x_horizon(2,:), '-x'); %[output:785034c0]
legend('\theta','\theta\_dot'); title('Open-loop State Trajectory from KKT'); %[output:785034c0]
grid on; %[output:785034c0]
subplot(3,1,2); %[output:785034c0]
stairs(0:N-1, u_horizon, 'LineWidth', 1.5); title('Open-Loop Control Sequence from KKT'); xlabel('k'); grid on; %[output:785034c0]
subplot(3,1,3); %[output:785034c0]
plot(x_horizon(1,:), x_horizon(2,:), 'LineWidth', 1.5); title('Open-loop Phase Plot from KKT'); xlabel('\theta'); ylabel('\theta\_dot'); grid on; %[output:785034c0]

% Simulate for 30 time steps, optimizing at each point with KKT function
% above

timesteps = 20;
x_cl2 = [x0, zeros(2,timesteps)];
u_applied2 = zeros(1,timesteps-1);

for i=1:timesteps

    % Get initial State for KKT Optimization. First loop, x_init = x0
    x_init = x_cl2(:,i);
    % Calculate horizon
    [u_horizon, x_horizon, p_horizon] = GetHorizon(x_init);
    % Apply first, find the next system state
    u_applied2(:,i) = u_horizon(:,1);
    x_cl2(:,i+1) = Ad*x_cl2(:,i) + Bd*u_applied2(:,i);

end

