subplot(3,1,2); %[output:689bbd6f]
stairs(0:timesteps-1, u_applied2, 'LineWidth', 1.5); title('Closed-Loop Control Inputs'); xlabel('Time Step (k)'); ylabel('Input Torque'); grid on; %[output:689bbd6f]
subplot(3,1,3); %[output:689bbd6f]
plot(x_cl2(1,:), x_cl2(2,:), 'LineWidth', 1.5); title('Closed-Loop Phase Plot from KKT'); xlabel('\theta'); ylabel('\theta\_dot'); grid on; %[output:689bbd6f]
