timesteps = 45;     % animate 35 time steps
Ts_plot = 0.25;     % seconds between frames

x_cl3 = zeros(2,timesteps+1);
x_cl3(:,1) = x0;
u_applied3 = zeros(1,timesteps);

figure; clf; %[output:3852f7e1]

% ------- STATE DEVELOPMENT subplot (top) -------
ax0 = subplot(3,1,1); hold on; grid on; %[output:3852f7e1]
title(ax0,'Theta (blue) & Theta rate (red) Evolution'); %[output:3852f7e1]
xlabel(ax0,'Time Step (k)'); %[output:3852f7e1]
ylabel('States (rad, rad/s)') %[output:3852f7e1]

% predicted state handle
pred_x_k_line    = plot(ax0,NaN,NaN,'b--','LineWidth',1.5); %[output:3852f7e1]
pred_xdot_k_line = plot(ax0,NaN,NaN,'r--','LineWidth',1.5); %[output:3852f7e1]

% ------- INPUT subplot (middle) -------
ax2 = subplot(3,1,2); hold on; grid on; %[output:3852f7e1]
title(ax2,'Inputs: Closed-loop (solid) + Predicted (dashed)'); %[output:3852f7e1]
xlabel(ax2,'Time Step (k)'); ylabel(ax2,'Input Torque (u)'); %[output:3852f7e1]
cl_input_line  = stairs(ax2,NaN,NaN,'b','LineWidth',2); %[output:3852f7e1]
pred_input_line = stairs(ax2,NaN,NaN,'r--','LineWidth',2); %[output:3852f7e1]

% ------- STATE subplot (bottom) -------
ax1 = subplot(3,1,3); hold on; grid on; %[output:3852f7e1]
title(ax1,'States: Closed-loop (solid) + Predicted (dashed)'); %[output:3852f7e1]
xlabel(ax1,'\theta'); ylabel(ax1,'\theta\_dot'); %[output:3852f7e1]
cl_state_line = plot(ax1,NaN,NaN,'b','LineWidth',2); %[output:3852f7e1]
pred_state_line = plot(ax1,NaN,NaN,'r--','LineWidth',2); %[output:3852f7e1]
% closed-loop handles
cl_x_k_line    = plot(ax0,NaN,NaN,'b','LineWidth',2);   % theta %[output:3852f7e1]
cl_xdot_k_line = plot(ax0,NaN,NaN,'r','LineWidth',2);   % theta_dot %[output:3852f7e1]

for k = 1:timesteps %[output:group:1e67ffa8]

    % ============================================================
    % 1) CLOSED-LOOP PROPAGATION
