%[text] **Problem 1.5: P-LQN Formulation & solution with quadprog.m**
%[text] 
%[text] There is no terminal constraint, and there is no state cost, so the optimal control input is **zero**. The controller has no requirement to balance the pendulum, and zero input over the time horizon minimizes the cost function.
%[text] 
%[text] ![](text:image:40d7)
%%
% % ChatGPT was used for this section of the script

% --- parameters (edit if needed) ---
Ts = 0.25;
N  = 20;           % horizon
nx = 2;            % state dimension
nu = 1;            % input dimension

% discrete system (your values)
A = [1 Ts; 0 1];
B = [0.5*Ts^2; Ts];

% initial condition x0 (example: pi/2, 0)
x0 = [pi/2; 0];

% --- decision variable sizes ---
nXvars = nx * N;         % x1..xN
nUvars = nu * N;         % u0..u_{N-1}
nVars  = nXvars + nUvars;

% --- cost: J = sum_{k=0}^{N-1} u_k^2 ---
H = zeros(nVars);
% put identity on the u-block:
u_idx = nXvars + (1:nUvars);      % column indices for u in z
H(u_idx,u_idx) = eye(nUvars);     % weight = 1 on each u_k
f = zeros(nVars,1);

% --- equality constraints: enforce dynamics x_{k+1} - A x_k - B u_k = 0 ---
Aeq = zeros(nx*N, nVars);
beq = zeros(nx*N, 1);

for k = 0:(N-1)
    row_idx = k*nx + (1:nx);         % rows for this dynamic equation (for x_{k+1})
    % column indices for x_{k+1} variable:
    col_xkp1 = (k)*nx + (1:nx);      % because x1 starts at index 1 when k=0

    % place +I on x_{k+1}
    Aeq(row_idx, col_xkp1) = eye(nx);

    % place -A on x_k (except when k==0; x0 is known)
    if k >= 1
        col_xk = (k-1)*nx + (1:nx);  % x_k variable column indices
        Aeq(row_idx, col_xk) = -A;
    end

    % place -B on u_k column
    col_uk = nXvars + k*nu + (1:nu);   % u_k column indices
    Aeq(row_idx, col_uk) = -B;

    % RHS: for k==0 move A*x0 to beq
    if k == 0
        beq(row_idx) = A * x0;
    else
        beq(row_idx) = zeros(nx,1);
    end
end

% no inequalities or bounds in this example
Aineq = [];
bineq = [];
lb = [];
ub = [];

% --- solve QP ---
opts = optimoptions('quadprog','Display','off');
z_opt = quadprog(H,f,Aineq,bineq,Aeq,beq,lb,ub,[],opts);

% --- parse result ---
X_opt = reshape(z_opt(1:nXvars), nx, N);    % columns are x1..xN
U_opt = z_opt(nXvars+1:end);                % u0..u_{N-1}

% include x0 to plot full state trajectory
X_full = [x0, X_opt];   % columns x0..xN

% quick plot (theta vs theta_dot phase plane)
figure; %[output:07eb253e]
plot(X_full(1,:), X_full(2,:), '-o'); %[output:07eb253e]
xlabel('\theta'); ylabel('\theta_dot'); %[output:07eb253e]
title('Phase plane (enforcing dynamics, no terminal equality)'); %[output:07eb253e]
grid on; %[output:07eb253e]


%[text] **ECE675 HW3 Problem 2:**
%[text] ![](text:image:549f)
%[text] **ECE675 HW3 Problem 3:**
%[text] ![](text:image:975e)
%[text] **Problem 3.1: Linearized Dynamics**
syms a0 a1 b0 x1 x2

% Linearize at x = [0; 0], cos(x1) --> 1, sin(x1) --> x1
A_lin = [0, 1; -a0, -a1] %[output:20b3f740]
B_lin = [0; b0] %[output:97d31433]

% Substitute in the numerical given values:
A_lin = double(subs(A_lin,[a0,a1,b0],[-2.5,0.05,0.25])) %[output:902f9f20]
B_lin = double(subs(B_lin,[a0,a1,b0],[-2.5,0.05,0.25])) %[output:013face1]
%[text] **Problem 3.2: Discretize the Dynamics:**
% Sample Rate
ts = 0.1;
% Intitial Cond.
x0 = [pi/4; 0];

% Define continuous system, build discrete ss system
ContLinSystem = ss(A_lin,B_lin,zeros(2,2),zeros(2,1)) %[output:556c5c7a]
DiscLinSystem = c2d(ContLinSystem,ts);

% Extract A & B for discrete system
Ad_lin = DiscLinSystem.A %[output:36c11538]
Bd_lin = DiscLinSystem.B %[output:8dd9403b]
Cd_lin = eye(2,2) %[output:355924fc]
Dd_lin = DiscLinSystem.D %[output:5ece982e]
%[text] **Problem 3.3: Discrete LQR Controller**
Q = [1 0; 0 0];
R = 1;

[K_dlqr, S, P] = dlqr(Ad_lin,Bd_lin,Q,R) %[output:269e4355] %[output:47030df2] %[output:3eca4874]

simout1 = sim('ECE675_HW3_Problem3_sim.mdl',[0 10]) %[output:5103a853]

theta = simout1.logsout{1}.Values.Data(:,1);
theta_dot = simout1.logsout{1}.Values.Data(:,2);
time = simout1.logsout{1}.Values.Time(:,1);
input = simout1.logsout{2}.Values.Data(:,1);

figure %[output:306862ab]
subplot(2,1,1) %[output:306862ab]
plot(time,theta) %[output:306862ab]
hold on %[output:306862ab]
plot(time, theta_dot) %[output:306862ab]
legend('\theta','d\theta/dt') %[output:306862ab]
grid on %[output:306862ab]
subplot(2,1,2) %[output:306862ab]
plot(time, input) %[output:306862ab]
ylim([-10,pi]) %[output:306862ab]
legend('Input u') %[output:306862ab]
title('dlqr Controller') %[output:306862ab]
grid on %[output:306862ab]
%[text] 
%%
%[text] **Problem 3.4: Dynamic Program Control Law**
% Get discrete LQR terminal cost matrix using dlqr (you already computed)
% [K_dlqr, S, ~] = dlqr(Ad_lin,Bd_lin,Q,R);   % S is solution of discrete riccati (use your existing S)

% params
X1GridSize = 10;
X2GridSize = X1GridSize;
DP_horizon = 20;
Q = [1 0; 0 0];
R = 1;
ts = 0.1;

% stage + terminal cost
Jstage = @(x,u) x'*Q*x + u'*R*u;
Jtogo = @(x) x'*S*x;

% state grid
X1 = linspace(-pi/2, pi/2, X1GridSize);
X2 = linspace(-pi/2, pi/2, X2GridSize);

% initialize tables for cost & optimal inputs
U = zeros(X1GridSize, X2GridSize);
J  = zeros(X1GridSize, X2GridSize);

% bounded u search grid
umax = 10; % control bounds should be within this pretty easily
u_grid = linspace(-umax, umax, 201);

% Value iteration
for iter = 1:DP_horizon
    for i = 1:length(X1)
        for j = 1:length(X2)
            x = [X1(i); X2(j)];

            % evaluate cost for every u candidate
            % next state
            Xnext = Ad_lin*x + Bd_lin * u_grid;   % 2 x numU
            % compute cost: stage + terminal-on-next
            cost_vals = zeros(size(u_grid));
            for m = 1:numel(u_grid)
                xn = Xnext(:,m);
                % evaluate Jtogo at xn via interp2 on J table (if iter>1)
                if iter==1
                    future_cost = Jtogo(xn);  % currently x'*S*x
                else
                    % safe interp: clamp xn to grid before interp
                    x1c = min(max(xn(1), min(X1)), max(X1));
                    x2c = min(max(xn(2), min(X2)), max(X2));
                    future_cost = interp2(X2, X1, J, x2c, x1c, 'linear');
                end
                cost_vals(m) = Jstage(x, u_grid(m)) + future_cost;
            end

            % pick best u
            [mincost, midx] = min(cost_vals);
            U(i,j) = u_grid(midx);
            J(i,j) = mincost;
        end
    end

    % update Jtogo to the just-computed J table
    % NOTE: J is arranged as J(i over X1, j over X2)
    Jtogo = @(xq) interp2(X2, X1, J, ...
                         min(max(xq(2), min(X2)), max(X2)), ...
                         min(max(xq(1), min(X1)), max(X1)), 'linear');
end

% DP policy accessor (with clamping)
function u = GetInput_DP(x_state, X1, X2, U)
    x1 = x_state(1);
    x2 = x_state(2);
    % clamp
    x1c = min(max(x1, min(X1)), max(X1));
    x2c = min(max(x2, min(X2)), max(X2));
    u = interp2(X2, X1, U, x2c, x1c, 'linear');
end

GetOptimalInput = @(x_state) GetInput_DP(x_state, X1, X2, U);

%% === Simulate closed-loop with DP policy ===
Tfinal = 10;
timesteps = round(Tfinal/ts);

x_cl_DP = zeros(2, timesteps+1);
u_cl_DP = zeros(1, timesteps);

x_cl_DP(:,1) = x0;

for k = 1:timesteps
    curx = x_cl_DP(:,k);
    u = GetOptimalInput(curx);
    u_cl_DP(k) = u;
    x_cl_DP(:,k+1) = Ad_lin*curx + Bd_lin*u;
end

t = 0:ts:Tfinal;

% plots
figure; %[output:132587d3]

subplot(2,1,1) %[output:132587d3]
plot(t, x_cl_DP(1,:), t, x_cl_DP(2,:)) %[output:132587d3]
grid on %[output:132587d3]
legend('x_1','x_2') %[output:132587d3]
title('DP Controller (Horizon=20, Reduced Grid Size)') %[output:132587d3]
ylabel('States') %[output:132587d3]

subplot(2,1,2) %[output:132587d3]
plot(t(1:end-1), u_cl_DP) %[output:132587d3]
grid on %[output:132587d3]
ylabel('u') %[output:132587d3]
xlabel('Time (s)') %[output:132587d3]
%[text] ![](text:image:4b31)
%[text] ![](text:image:4aca)
%[text] ![](text:image:2fa2)
%[text] ![](text:image:4592)
%%
%[text] ![](text:image:3bcc)
%[text] Closed loop response with quadprog is very similar to response using the DP control law with reduced grid size (10x10 grid). Increased grid size on the DP controller significantly reduces the control effort to bring the pendulum to upright position.

function u_opt = GetOptimalInputQP(x, Ad, Bd, Q, R, P)

% state-dependent
Ax = Ad * x;

% quad term
H = Bd' * P * Bd + R;
H = (H + H')/2;

% linear term
f = (Bd' * P * Ax);

% solve QP
u_opt = quadprog(H, f, [], [], [], [], [], [], [], ...
                 optimoptions('quadprog','Display','off'));

end

DP_horizon = 20;
Q = [1 0; 0 0];
R = 1;
P = zeros(2,2) %[output:79d57723]
ts = 0.1;

GetOptimalInputQPAnon = @(x) GetOptimalInputQP(x, Ad, Bd, Q, R, P) %[output:6e1addf3]

Tfinal = 10;
timesteps = round(Tfinal/ts);

x_cl_QP = zeros(2, timesteps+1);
u_cl_QP = zeros(1, timesteps);

x_cl_QP(:,1) = x0;

for k = 1:timesteps
    curx = x_cl_QP(:,k);
    u = GetOptimalInput(curx);
    u_cl_QP(k) = u;
    x_cl_QP(:,k+1) = Ad_lin*curx + Bd_lin*u;
end

t = 0:ts:Tfinal;

% plots
figure; %[output:7c806581]

subplot(2,1,1) %[output:7c806581]
plot(t, x_cl_QP(1,:), t, x_cl_QP(2,:)) %[output:7c806581]
grid on %[output:7c806581]
legend('x_1','x_2') %[output:7c806581]
title('QP Controller') %[output:7c806581]
ylabel('States') %[output:7c806581]

subplot(2,1,2) %[output:7c806581]
plot(t(1:end-1), u_cl_QP) %[output:7c806581]
grid on %[output:7c806581]
ylabel('u') %[output:7c806581]
xlabel('Time (s)') %[output:7c806581]


